set-header.value:
@{
        var authHeader = context.Request.Headers.GetValueOrDefault("X-Original-Authorization","");
        if (string.IsNullOrEmpty(authHeader)) return "";
        try {
          var token = authHeader.Split(' ').Last();
          var parts = token.Split('.');
          if (parts.Length != 3) return "";
          var payload = parts[1];
          var padded = payload.PadRight(payload.Length + (4 - payload.Length % 4) % 4, '=');
          var decoded = System.Text.Encoding.UTF8.GetString(Convert.FromBase64String(padded));
          var json = Newtonsoft.Json.Linq.JObject.Parse(decoded);
          return json["upn"]?.ToString() ?? json["email"]?.ToString() ?? "";
        } catch {
          return "";
        }
      }

return-response.set-body:
@{
            return new Newtonsoft.Json.Linq.JObject(
              new Newtonsoft.Json.Linq.JProperty("error", "unauthorized"),
              new Newtonsoft.Json.Linq.JProperty("error_description", "Authentication failed. Please provide a valid Entra ID access token."),
              new Newtonsoft.Json.Linq.JProperty("details", context.LastError.Message)
            ).ToString();
          }
